const express = require('express');
const axios = require('axios');

const app = express();
const port = 3000;

app.use(express.json());

app.post('/verify-bvn', async (req, res) => {
  const { bvn } = req.body;

  if (!bvn) {
    return res.status(400).json({ error: 'BVN is required' });
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/bvn',
      { bvn },
      {
        headers: {
          'app-id': process.env.PREMBLY_APP_ID || '',
          'x-api-key': process.env.PREMBLY_API_KEY || '',
          'Content-Type': 'application/json'
        }
      }
    );

    res.json(response.data);
  } catch (error) {
    if (error.response) {
      res.status(error.response.status).json(error.response.data);
    } else {
      res.status(500).json({ error: 'An error occurred while verifying the BVN' });
    }
  }
});

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

